foreach ($iterable as $key => $item) {
    if ($isFirstItem) {
        $isFirstItem = false;
        // depending on the first elements key the generator is detected as a list or map
        // we can not check for a whole list or map because that would hurt the performance
        // of the streamed response which is the main goal of this response class
        if (0 !== $key) {
            $startTag = '{';
        }

        echo $startTag;
    } else {
        // if not first element of the generic, a separator is required between the elements
        echo ',';
    }

    if ('{' === $startTag) {
        echo json_encode((string) $key, $keyEncodingOptions).':';
    }

    $this->streamData($item, $jsonEncodingOptions, $keyEncodingOptions);
}

if ($hasLarastan) {
	if ($isLaravelLast) {
		$message .= "\n";
		$message .= "\n" . 'This message is coming from Laravel Framework itself.';
		$message .= "\n" . 'Larastan boots up your application in order to provide';
		$message .= "\n" . 'smarter static analysis of your codebase.';
		$message .= "\n";
		$message .= "\n" . 'In order to do that, the environment you run PHPStan in';
		$message .= "\n" . 'must match the environment you run your application in.';
		$message .= "\n";
		$message .= "\n" . 'Make sure you\'ve set your environment variables';
		$message .= "\n" . 'or the .env file correctly.';

		return $message;
	}

	$bugReportUrl = 'https://github.com/larastan/larastan/issues/new?template=bug-report.md';
} else {
	$bugReportUrl = 'https://github.com/phpstan/phpstan/issues/new?template=Bug_report.yaml';
}

if ($sameColumns) {
    if (! $this->samePartialIndex($other)) {
        return false;
    }

    if (! $this->hasSameColumnLengths($other)) {
        return false;
    }

    if (! $this->isUnique() && ! $this->isPrimary()) {
        // this is a special case: If the current key is neither primary or unique, any unique or
        // primary key will always have the same effect for the index and there cannot be any constraint
        // overlaps. This means a primary or unique index can always fulfill the requirements of just an
        // index that has no constraints.
        return true;
    }

    if ($other->isPrimary() !== $this->isPrimary()) {
        return false;
    }

    return $other->isUnique() === $this->isUnique();
}

final class UnsupportedSchema extends RuntimeException implements SchemaException
{
    public static function sqliteMissingForeignKeyConstraintReferencedColumns(
        ?string $constraintName,
        string $referencingTableName,
        string $referencedTableName,
    ): self {
        if ($constraintName !== null) {
            $constraintReference = sprintf('"%s"', $constraintName);
        } else {
            $constraintReference = '<unnamed>';
        }

        return new self(sprintf(
            'Unable to introspect foreign key constraint %s on table "%s" because the referenced column names'
                . ' are omitted, and the referenced table "%s" does not exist or does not have a primary key.',
            $constraintReference,
            $referencingTableName,
            $referencedTableName,
        ));
    }
}
